/* Resolves a period toggle's selection to a concrete date range, so a label
   like "Last 7 days" reads as "May 20 – May 26 · 7 days". Anchored to a fixed
   demo "today" (the prototype runs on May-2026 data) so ranges stay sensible
   regardless of the real clock. Swap DEMO_TODAY for `new Date()` when live. */

export type PeriodKey =
  | "mtd"
  | "lastmonth"
  | "last7"
  | "last30"
  | "last90"
  | "last6mo"
  | "last12mo"
  | "ytd"
  | "custom";

const DEMO_TODAY = new Date(2026, 4, 26); // May 26, 2026
const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const DAY = 86400000;

const fmt = (d: Date, withYear = false) =>
  `${MONTHS[d.getMonth()]} ${d.getDate()}${withYear ? `, ${d.getFullYear()}` : ""}`;

const addDays = (d: Date, n: number) => {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
};

const dayCount = (start: Date, end: Date) => Math.round((end.getTime() - start.getTime()) / DAY) + 1;

export interface ResolvedRange {
  text: string;
  count: string;
}

export function resolvePeriodRange(key: PeriodKey, today: Date = DEMO_TODAY): ResolvedRange {
  const y = today.getFullYear();
  const span = (start: Date, count: string): ResolvedRange => {
    const cy = start.getFullYear() !== y;
    return { text: `${fmt(start, cy)} – ${fmt(today, cy)}`, count };
  };
  switch (key) {
    case "mtd": {
      const start = new Date(y, today.getMonth(), 1);
      return span(start, `· ${today.getDate()} days`);
    }
    case "lastmonth": {
      const start = new Date(y, today.getMonth() - 1, 1);
      const end = new Date(y, today.getMonth(), 0); // last day of previous month
      const cy = start.getFullYear() !== y;
      return { text: `${fmt(start, cy)} – ${fmt(end, cy)}`, count: `· ${end.getDate()} days` };
    }
    case "last7":
      return span(addDays(today, -6), "· 7 days");
    case "last30":
      return span(addDays(today, -29), "· 30 days");
    case "last90":
      return span(addDays(today, -89), "· 90 days");
    case "ytd": {
      const start = new Date(y, 0, 1);
      return span(start, `· ${dayCount(start, today)} days`);
    }
    case "last6mo": {
      const start = new Date(y, today.getMonth() - 6, today.getDate());
      return { text: `${fmt(start, true)} – ${fmt(today, true)}`, count: "· 6 months" };
    }
    case "last12mo": {
      const start = new Date(y - 1, today.getMonth(), today.getDate());
      return { text: `${fmt(start, true)} – ${fmt(today, true)}`, count: "· 12 months" };
    }
    case "custom":
      return { text: "Pick dates", count: "" };
  }
}

/* Map toggle labels → period keys (case-insensitive). Lets pages pass just an
   accent; the date chip appears only when every label is a recognized period
   (so device toggles like "Desktop/Mobile" or forecast horizons like
   "Next 30 days" simply get no chip). */
const LABEL_TO_KEY: Record<string, PeriodKey> = {
  mtd: "mtd",
  "this month": "mtd",
  "last month": "lastmonth",
  "7 days": "last7",
  "last 7 days": "last7",
  "30 days": "last30",
  "last 30 days": "last30",
  "90 days": "last90",
  "last 90 days": "last90",
  "last 6 months": "last6mo",
  "last 12 months": "last12mo",
  "year to date": "ytd",
  ytd: "ytd",
  custom: "custom",
};

/** Returns a parallel key array if EVERY label is a recognized period, else null. */
export function inferKeys(labels: string[]): PeriodKey[] | null {
  const out: PeriodKey[] = [];
  for (const l of labels) {
    const k = LABEL_TO_KEY[l.trim().toLowerCase()];
    if (!k) return null;
    out.push(k);
  }
  return out;
}
